import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { useAuth } from '../../contexts/AuthContext';
import { MessageCircle, Send, Users, Search, Paperclip, Smile, MoreVertical } from 'lucide-react';

const ChatInterno = () => {
  const { admin } = useAuth();
  const [mensagens, setMensagens] = useState([]);
  const [novaMensagem, setNovaMensagem] = useState('');
  const [funcionarios, setFuncionarios] = useState([]);
  const [destinatarioSelecionado, setDestinatarioSelecionado] = useState(null);
  const [busca, setBusca] = useState('');
  const [modoGrupo, setModoGrupo] = useState(false);
  const messagesEndRef = useRef(null);
  const wsRef = useRef(null);

  useEffect(() => {
    loadFuncionarios();
    connectWebSocket();
    return () => {
      if (wsRef.current) wsRef.current.close();
    };
  }, []);

  useEffect(() => {
    if (destinatarioSelecionado) {
      loadMensagens();
    }
  }, [destinatarioSelecionado]);

  useEffect(() => {
    scrollToBottom();
  }, [mensagens]);

  const connectWebSocket = () => {
    const token = localStorage.getItem('adminToken');
    const wsUrl = `${window.location.protocol === 'https:' ? 'wss:' : 'ws:'}//${window.location.host}/ws/chat-interno?token=${token}`;

    const ws = new WebSocket(wsUrl);

    ws.onopen = () => console.log('Chat interno conectado');

    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
      if (data.type === 'nova_mensagem') {
        if (destinatarioSelecionado && 
            (data.de === destinatarioSelecionado.id || data.para === destinatarioSelecionado.id)) {
          setMensagens(prev => [...prev, data]);
        }
      }
    };

    ws.onerror = (error) => console.error('WebSocket erro:', error);
    ws.onclose = () => {
      console.log('WebSocket fechado, reconectando...');
      setTimeout(connectWebSocket, 3000);
    };

    wsRef.current = ws;
  };

  const loadFuncionarios = async () => {
    try {
      const res = await axios.get('/api/admin/funcionarios');
      setFuncionarios(res.data.filter(f => f.ativo && f.id !== admin?.id));
    } catch (err) {
      console.error('Erro ao carregar funcionários:', err);
    }
  };

  const loadMensagens = async () => {
    if (!destinatarioSelecionado) return;
    try {
      const res = await axios.get(`/api/admin/chat-interno/mensagens/${destinatarioSelecionado.id}`);
      setMensagens(res.data || []);
    } catch (err) {
      console.error('Erro ao carregar mensagens:', err);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleEnviar = async (e) => {
    e.preventDefault();
    if (!novaMensagem.trim() || !destinatarioSelecionado) return;

    try {
      const payload = {
        para: modoGrupo ? 'todos' : destinatarioSelecionado.id,
        mensagem: novaMensagem.trim(),
      };

      if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
        wsRef.current.send(JSON.stringify({ type: 'enviar', ...payload }));
      } else {
        await axios.post('/api/admin/chat-interno/enviar', payload);
      }

      setNovaMensagem('');
    } catch (err) {
      alert('Erro ao enviar mensagem: ' + (err.response?.data?.detail || 'Erro'));
    }
  };

  const funcionariosFiltrados = funcionarios.filter(f =>
    f.nome.toLowerCase().includes(busca.toLowerCase()) ||
    f.usuario.toLowerCase().includes(busca.toLowerCase())
  );

  const formatarHora = (dataStr) => {
    if (!dataStr) return '';
    const data = new Date(dataStr);
    return data.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  };

  const formatarData = (dataStr) => {
    if (!dataStr) return '';
    const data = new Date(dataStr);
    const hoje = new Date();
    const ontem = new Date(hoje);
    ontem.setDate(ontem.getDate() - 1);

    if (data.toDateString() === hoje.toDateString()) return 'Hoje';
    if (data.toDateString() === ontem.toDateString()) return 'Ontem';
    return data.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
  };

  return (
    <div className="h-[calc(100vh-120px)] flex bg-gray-50">
      {/* Sidebar - Lista de conversas */}
      <div className="w-80 bg-white border-r border-gray-200 flex flex-col">
        <div className="p-4 border-b border-gray-200">
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
              <MessageCircle className="h-5 w-5 text-blue-600" />
              Chat Interno
            </h2>
            <button
              onClick={() => setModoGrupo(!modoGrupo)}
              className={`p-2 rounded-lg transition-colors ${modoGrupo ? 'bg-blue-100 text-blue-600' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}
              title={modoGrupo ? 'Modo grupo ativo' : 'Modo individual'}
            >
              <Users className="h-5 w-5" />
            </button>
          </div>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
            <input
              type="text"
              placeholder="Buscar funcionário..."
              value={busca}
              onChange={(e) => setBusca(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto">
          {modoGrupo && (
            <div
              onClick={() => setDestinatarioSelecionado({ id: 'todos', nome: 'Grupo Geral', usuario: 'todos' })}
              className={`p-3 border-b border-gray-100 cursor-pointer transition-colors ${
                destinatarioSelecionado?.id === 'todos' ? 'bg-blue-50' : 'hover:bg-gray-50'
              }`}
            >
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-gradient-to-br from-blue-500 to-purple-500 rounded-full flex items-center justify-center">
                  <Users className="h-6 w-6 text-white" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-gray-900">Grupo Geral</p>
                  <p className="text-xs text-gray-500">Todos os funcionários</p>
                </div>
              </div>
            </div>
          )}

          {funcionariosFiltrados.map((func) => (
            <div
              key={func.id}
              onClick={() => setDestinatarioSelecionado(func)}
              className={`p-3 border-b border-gray-100 cursor-pointer transition-colors ${
                destinatarioSelecionado?.id === func.id ? 'bg-blue-50' : 'hover:bg-gray-50'
              }`}
            >
              <div className="flex items-center gap-3">
                <div className="relative">
                  <div className="w-12 h-12 bg-gradient-to-br from-indigo-500 to-blue-500 rounded-full flex items-center justify-center">
                    <span className="text-white font-bold text-lg">
                      {func.nome.charAt(0).toUpperCase()}
                    </span>
                  </div>
                  <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white rounded-full"></div>
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-gray-900 truncate">{func.nome}</p>
                  <p className="text-xs text-gray-500 truncate">@{func.usuario}</p>
                </div>
              </div>
            </div>
          ))}

          {funcionariosFiltrados.length === 0 && (
            <div className="p-8 text-center text-gray-400">
              <Users className="h-12 w-12 mx-auto mb-2 opacity-50" />
              <p className="text-sm">Nenhum funcionário encontrado</p>
            </div>
          )}
        </div>
      </div>

      {/* Área de chat */}
      <div className="flex-1 flex flex-col bg-gray-50">
        {destinatarioSelecionado ? (
          <>
            {/* Header do chat */}
            <div className="bg-white border-b border-gray-200 p-4 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-blue-500 rounded-full flex items-center justify-center">
                  {destinatarioSelecionado.id === 'todos' ? (
                    <Users className="h-5 w-5 text-white" />
                  ) : (
                    <span className="text-white font-bold">
                      {destinatarioSelecionado.nome.charAt(0).toUpperCase()}
                    </span>
                  )}
                </div>
                <div>
                  <p className="font-semibold text-gray-900">{destinatarioSelecionado.nome}</p>
                  <p className="text-xs text-green-600">Online</p>
                </div>
              </div>
              <button className="p-2 hover:bg-gray-100 rounded-lg transition-colors">
                <MoreVertical className="h-5 w-5 text-gray-600" />
              </button>
            </div>

            {/* Mensagens */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-[url('data:image/svg+xml;base64,')]">
              {mensagens.map((msg, idx) => {
                const ehMinha = msg.de === admin?.id;
                const mostrarData = idx === 0 || formatarData(msg.data_criacao) !== formatarData(mensagens[idx - 1]?.data_criacao);

                return (
                  <React.Fragment key={msg.id || idx}>
                    {mostrarData && (
                      <div className="flex justify-center my-4">
                        <span className="bg-white px-3 py-1 rounded-full text-xs text-gray-500 shadow-sm">
                          {formatarData(msg.data_criacao)}
                        </span>
                      </div>
                    )}
                    <div className={`flex ${ehMinha ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-md px-4 py-2 rounded-2xl shadow-sm ${
                        ehMinha
                          ? 'bg-blue-500 text-white rounded-br-md'
                          : 'bg-white text-gray-900 rounded-bl-md'
                      }`}>
                        {!ehMinha && msg.de_nome && (
                          <p className="text-xs font-semibold text-blue-600 mb-1">{msg.de_nome}</p>
                        )}
                        <p className="text-sm whitespace-pre-wrap break-words">{msg.mensagem}</p>
                        <div className={`flex items-center justify-end gap-1 mt-1 ${
                          ehMinha ? 'text-blue-100' : 'text-gray-400'
                        }`}>
                          <span className="text-[10px]">{formatarHora(msg.data_criacao)}</span>
                        </div>
                      </div>
                    </div>
                  </React.Fragment>
                );
              })}
              <div ref={messagesEndRef} />
            </div>

            {/* Input de mensagem */}
            <div className="bg-white border-t border-gray-200 p-4">
              <form onSubmit={handleEnviar} className="flex items-center gap-2">
                <button type="button" className="p-2 hover:bg-gray-100 rounded-lg transition-colors">
                  <Smile className="h-5 w-5 text-gray-600" />
                </button>
                <button type="button" className="p-2 hover:bg-gray-100 rounded-lg transition-colors">
                  <Paperclip className="h-5 w-5 text-gray-600" />
                </button>
                <input
                  type="text"
                  value={novaMensagem}
                  onChange={(e) => setNovaMensagem(e.target.value)}
                  placeholder="Digite uma mensagem..."
                  className="flex-1 px-4 py-2 border border-gray-300 rounded-full focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
                <button
                  type="submit"
                  disabled={!novaMensagem.trim()}
                  className="p-3 bg-blue-500 text-white rounded-full hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                  <Send className="h-5 w-5" />
                </button>
              </form>
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <MessageCircle className="h-16 w-16 text-gray-300 mx-auto mb-4" />
              <p className="text-gray-500 text-lg font-medium">Selecione uma conversa</p>
              <p className="text-gray-400 text-sm mt-1">Escolha um funcionário para começar a conversar</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ChatInterno;
